import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

CHRIST = {
"30": {
"1": "<p>A shadow: Moses addresses the tribal heads with the law of vows — establishing that a man who makes a vow to YHWH must not break his word (<em>lo yachel devaro</em>). The principle of inviolable speech points toward Christ, whose every word is absolutely reliable: 'heaven and earth will pass away, but my words will not pass away' (Matt 24:35). Christ is the one person whose vow is utterly unbreakable by nature.</p>",
"2": "<p>A direct type: 'Everything that proceeds out of his mouth he shall do.' The absolute correspondence between word and act in vow-keeping is the standard Christ perfectly embodies. He 'fulfills all righteousness' (Matt 3:15) — every obligation, every requirement is met in him. His words are deeds; his promises are certainties. 'He who promised is faithful' (Heb 10:23).</p>",
"3": "<p>A shadow: A woman in her father's house who makes a vow — the father can annul it if he hears it on the same day. The father's authority over his daughter's vow foreshadows the Father's sovereignty over those under his care. But Christ, as the one who comes from the Father's house, has a vow the Father ratifies — his entire mission is the Father's will: 'I have come down from heaven, not to do my own will but the will of him who sent me' (John 6:38).</p>",
"4": "<p>A theme: If the father hears and holds his peace, all her vows stand. Silence ratifies the vow. The Father's public ratification of Christ at his baptism — 'This is my beloved Son, with whom I am well pleased' (Matt 3:17) — is the ultimate vow-ratification: the Father's loud endorsement of the Son's entire mission.</p>",
"5": "<p>A theme: But if the father annuls it on the day he hears, YHWH will forgive her because the father annulled it. The protection of the one under covering: her vow that was beyond her ability to keep is cancelled, not held against her. Christ fulfills the obligations his people cannot keep — 'he himself bore our sins in his body' (1 Pet 2:24). The legal obligation that was beyond us is removed because the one over us bore it.</p>",
"6": "<p>A shadow: A woman makes a vow and then marries — the husband hears on the day of marriage and holds his peace, and her vows stand. Marriage ratifies the vow. Paul's image of Christ as husband of the church (Eph 5:25-27): Christ the bridegroom takes the church with her imperfect vows, ratifies what he can and absorbs what he cannot. He 'loved the church and gave himself up for her.'</p>",
"7": "<p>A theme: If the husband hears and holds his peace on the day he hears, then her vows stand. The husband's silence is consent; his voice is decision. Christ's silence before Pilate (Matt 27:14) was not passive — it was purposeful surrender: he did not defend himself because the cup was his to drink. His silence was the loudest possible act of will.</p>",
"8": "<p>A shadow: If the husband annuls the vow on the day he hears, he has made void the obligation incurred by her lips, and YHWH will forgive her. The husband bears the cost of annulment — the wife goes free, but the vow's weight transfers to him. Christ bears what his church could not: 'the LORD has laid on him the iniquity of us all' (Isa 53:6). The church is freed; Christ absorbs the cost.</p>",
"9": "<p>A direct type: The vow of a widow or a divorced woman stands — she is not under a man's authority and bears her vow directly before YHWH. The widow stands unmediated before God: her word is her bond, and YHWH receives it directly. The church after Christ's death and before his return is in an analogous position: between the crucifixion and the consummation, it stands directly before the Father through the Spirit (Rom 8:26-27).</p>",
"10": "<p>A theme: A vow made while still in her husband's house binds her. The prior commitments made while under covering remain. The church's promises made in union with Christ bind her to the standard of that union: 'do you not know that your bodies are members of Christ?' (1 Cor 6:15). What is done in union with Christ is done in the presence of the absolute standard.</p>",
"11": "<p>A shadow: If the husband heard and held his peace on the day she vowed and the days passed — the silence of sustained days ratifies the vow. The patience of the covenant-keeper who neither annuls nor abandons. Christ's patience with the church across the centuries: 'The Lord is not slow to fulfill his promise as some count slowness, but is patient toward you, not wishing that any should perish' (2 Pet 3:9).</p>",
"12": "<p>A theme: If the husband annuls after silence, he bears her iniquity. The annulment after the fact — reneging — creates guilt in the one who renged. Christ does not renege. 'Having loved his own who were in the world, he loved them to the end' (John 13:1). The surety who makes a promise and keeps it through every pressure is the anti-type of the husband who annulled after silence.</p>",
"13": "<p>A theme: Every vow and every binding oath to afflict oneself — the husband can establish or annul. The power of self-denial vows (fasting, Nazirite dedication) under covenant authority. Christ's own self-denial — 'not my will but yours' (Luke 22:42) — is the ultimate self-affliction vow ratified by the Father and accomplished completely.</p>",
"14": "<p>A shadow: If the husband holds his peace from day to day, he confirms all her vows — by saying nothing he establishes them all. The silent ratification over extended time. God's patience across Old Testament centuries — holding peace through Israel's ups and downs, confirming the covenant through sustained silence before the appointed hour — until 'when the fullness of time had come, God sent forth his Son' (Gal 4:4).</p>",
"15": "<p>A theme: If he annuls them after he has heard, then he shall bear her iniquity. The covenant head who fails to bear what was his to bear incurs guilt. Christ, the covenant head who bears all that was ours, never incurs this guilt — because he holds nothing back from bearing. 'He who did not spare his own Son but gave him up for us all, how will he not also with him graciously give us all things?' (Rom 8:32).</p>",
"16": "<p>A shadow: These are the statutes that YHWH commanded Moses, between a man and his wife, and between a father and his daughter while still in her youth in her father's house. The covenant architecture of vows — the web of ratification, bearing, and accountability — is the Old Testament form of what Paul describes as the Christ-church marriage: covenant obligations with a head who bears what the other cannot. 'The husband is the head of the wife even as Christ is the head of the church' (Eph 5:23).</p>"
},
"31": {
"1": "<p>A shadow: YHWH commands Moses to execute vengeance on Midian before his death. The war of vengeance (<em>niqmat YHWH</em> — vengeance of YHWH) is not Moses's personal retaliation but divine justice for the Baal-Peor seduction. Christ will execute the final judgment on those who have seduced the church (Rev 19:11-15): 'In righteousness he judges and makes war.' Divine vengeance, properly understood, is always in service of righteousness, not passion.</p>",
"2": "<p>A theme: 'After that you shall be gathered to your people.' Moses's own death is linked to the completion of this final task. The servant must complete the assigned work before resting. Christ 'who for the joy set before him endured the cross' (Heb 12:2) completed his work before the resurrection rest: 'It is finished' (John 19:30). The death that followed was the gathering, not the defeat.</p>",
"3": "<p>A shadow: Moses instructs the people to arm men from among them for YHWH's war against Midian. The warriors are 'from among the people' — not angels, not a separate force, but men drawn out of the community and sent. Christ sends his disciples as his warriors: 'As the Father has sent me, even so I am sending you' (John 20:21). The church is the army recruited from the community.</p>",
"4": "<p>A shadow: A thousand from each tribe — twelve thousand total. The twelve-tribe completeness mirrors the twelve apostles sent to gather the whole Israel: 'you will sit on twelve thrones, judging the twelve tribes of Israel' (Matt 19:28). The twelve-part structure of representation recurs throughout salvation history as the sign of complete, covenantal Israel.</p>",
"5": "<p>A theme: Twelve thousand equipped for battle from the thousands of Israel. The ones who go to war are drawn from the larger community they represent. The few going for the many — the principle of representative action. Christ goes as the representative of humanity: 'as by a man came death, by a man has come also the resurrection of the dead' (1 Cor 15:21). One for all; all in the one.</p>",
"6": "<p>A direct type: Phinehas son of Eleazar goes to battle with the holy vessels and the trumpets for signaling. Phinehas — who turned back the divine wrath at Baal-Peor through his zealous act (Num 25:11) — leads the war with priestly authority. The priestly warrior who made atonement and now leads the battle of judgment is a type of Christ: high priest and warrior-king combined. 'He is the propitiation for our sins' (1 John 2:2) and 'King of kings and Lord of lords' (Rev 19:16).</p>",
"7": "<p>A shadow: They warred against Midian as YHWH commanded Moses, and killed every male. The total defeat of the enemy who seduced Israel foreshadows the eschatological judgment on every power that has led the church astray. Revelation 20:10: 'the devil who had deceived them was thrown into the lake of fire.' The defeat of Midian is the temporal earnest of the final judgment on deception.</p>",
"8": "<p>A direct type: They killed the five kings of Midian and Balaam son of Beor with the sword. Balaam — who could not curse Israel by oracle — was finally destroyed by the sword of the God he claimed to serve. The false prophet who used the name of YHWH for profit met the fate of all such: 'false prophets... will face swift destruction' (2 Pet 2:1). Christ judges the Balaam-like: 'I have a few things against you: you have some there who hold the teaching of Balaam' (Rev 2:14).</p>",
"9": "<p>A shadow: The Israelites took the Midianite women and children captive, and their animals and all their goods. The capture of the enemy's dependents and property — the extension of victory beyond the battlefield. Christ's victory extends beyond defeating sin to claiming what sin had taken: 'he led captivity captive' (Eph 4:8, quoting Ps 68:18). The spoils of victory are given as gifts to the church.</p>",
"10": "<p>A shadow: All the towns and encampments were burned with fire. The complete destruction of the settled infrastructure of the enemy. In Revelation's imagery, Babylon falls and 'smoke goes up from her forever and ever' (Rev 19:3). The burning of Midian's towns is the temporal type of the eschatological burning of the city built on seduction and idolatry.</p>",
"11": "<p>A shadow: They took all the plunder, all the spoils both of people and animals. The spoils of war taken in full — nothing left to the defeated enemy. Christ's resurrection is the ultimate taking of spoils: 'when he ascended on high he led a host of captives' (Eph 4:8). The one who descended into the depths and ascended to the heights took what was rightfully his.</p>",
"12": "<p>A theme: They bring the captives and spoils and plunder to Moses and Eleazar the priest and to the congregation at the plains of Moab. The victors return to the covenant community and its leadership — the spoils are not privatized but brought to the whole assembly. Christ's victory is for the church, not for a private benefit: 'to each one of us grace has been given according to the measure of Christ's gift' (Eph 4:7).</p>",
"13": "<p>A shadow: Moses and Eleazar and all the leaders of the congregation went out to meet them outside the camp. The returning warriors welcomed by the whole leadership — a triumphal entry. Christ's triumphal entry into Jerusalem (Matt 21) echoes this structure: the returning one welcomed by the community, palms and hosannas replacing the assembled leaders and plunder.</p>",
"14": "<p>A theme: Moses is angry with the officers who had kept all the women alive. The women of Moab and Midian were the agents of the Baal-Peor seduction (Num 25:1-2). The judgment was not on innocent bystanders but on the specific agents of spiritual corruption. Christ's judgment is similarly targeted: 'woe to the one through whom temptations come' (Matt 18:7). Compassion and judgment are not opposed; they are ordered by the nature of what is being judged.</p>",
"15": "<p>A theme: 'Have you let all the women live? These are the very ones who... caused the Israelites to be unfaithful to the LORD at Baal-Peor.' The accountability for spiritual corruption is laid directly at the feet of those who caused it. Jude 11 uses Balaam's error as the paradigm for those who 'for the sake of gain... rushed into Balaam's error.' False teaching for profit is a species of this sin.</p>",
"16": "<p>A direct type: The women who caused the plague through Balaam's advice must be judged. Balaam's strategy — which direct cursing failed to achieve — was finally accomplished through seduction (Rev 2:14: 'the teaching of Balaam, who taught Balak to put a stumbling block before the sons of Israel, so that they might eat food sacrificed to idols and practice sexual immorality'). Christ's message to the churches warns against exactly this: those who seduce the church from within are judged more severely than external enemies.</p>",
"17": "<p>A shadow: Only the young girls who have not known a man are spared. The innocents — those who had not participated in the seduction — are protected. The principle of individual accountability: 'the soul who sins shall die; the son shall not suffer for the iniquity of the father, nor the father suffer for the iniquity of the son' (Ezek 18:20). Christ extends mercy exactly as far as guilt reaches, no further.</p>",
"18": "<p>A theme: Keep the young girls alive for yourselves. The preserved girls become part of Israel — adopted into the covenant people. This foreshadows the gentile inclusion into the covenant community: those who had no prior standing in Israel are received into it through the victory of YHWH's people. 'Once you were not a people, but now you are God's people' (1 Pet 2:10).</p>",
"19": "<p>A shadow: Anyone who has killed a person or touched a corpse must remain outside the camp seven days. The purification requirement for those who engaged in the killing — even righteous killing in YHWH's war creates impurity. Christ's engagement with sin and death — though perfectly righteous — required the full bearing of death's weight: his descent into death itself (Acts 2:27). The seven-day purification becomes the three-day and then-resurrection pattern.</p>",
"20": "<p>A shadow: Every garment, leather article, goat hair, and wooden article must be purified. The material goods taken in battle must be cleansed before entering the camp. The material world affected by sin and death requires purification before it can belong to the holy community. 'Then comes the end, when he delivers the kingdom to God the Father after destroying every rule and every authority and power' (1 Cor 15:24). The purified creation is handed back to the Father.</p>",
"21": "<p>A shadow: Eleazar the priest gives the law of purification to the warriors: gold, silver, bronze, iron, tin, and lead — whatever can endure fire shall be purified through fire. The law of metal purification is Eleazar's responsibility as high priest. Christ as eternal high priest gives the law of purification that governs his own people: 'he himself will baptize you with the Holy Spirit and fire' (Matt 3:11).</p>",
"22": "<p>A direct type: The metals that endure fire are purified through fire; those that cannot must be purified through water. The two purification agents — fire and water — correspond to the Spirit (fire) and baptism (water). 'Unless one is born of water and the Spirit, he cannot enter the kingdom of God' (John 3:5). The metal purification is a material type of the double purification Christ brings.</p>",
"23": "<p>A theme: 'And it shall be clean. Nevertheless, it shall also be purified with the water of purification.' Both fire and water required — not either/or. The double purification is thorough, comprehensive. Christ's atonement is similarly comprehensive: his blood cleanses, and his Spirit renews. The external (water of purification) and the internal (fire) together constitute complete purification.</p>",
"24": "<p>A theme: Wash your clothes on the seventh day and be clean; then you may come into the camp. The seventh day — Sabbath — as the culmination of purification. After the labor of war and the days of cleansing, the Sabbath reception back into the community. Christ's resurrection on the first day (the 'eighth day' = new Sabbath) receives the purified back into the kingdom community after the labor of salvation history.</p>",
"25": "<p>A shadow: YHWH tells Moses to count the plunder with Eleazar the priest and the tribal heads. The careful accounting of what was won in battle — nothing is lost or unaccounted for. Christ accounts for every member of his flock: 'of those you gave me I have not lost one' (John 18:9). The shepherd counts the sheep; the priest counts the plunder. Nothing is left unaccounted.</p>",
"26": "<p>A theme: Take a total of the plunder — of both people and animals — you and Eleazar the priest and the family heads. The whole leadership involved in the accounting: no single person controls the spoils of victory. The distribution of Christ's victory gifts involves the whole body: 'to each one individually as he wills' (1 Cor 12:11).</p>",
"27": "<p>A shadow: Divide the plunder evenly between the warriors who went to battle and the rest of the congregation. The fundamental principle: the whole community shares in what the few won. Those who stayed with the supplies share equally with those who fought (1 Sam 30:24 formalizes this same principle under David). In Christ's victory, those who were weak and remained share equally in the resurrection inheritance: 'if children, then heirs — heirs of God and fellow heirs with Christ' (Rom 8:17).</p>",
"28": "<p>A shadow: Levy for YHWH one out of every five hundred from the warriors' half — of persons, cattle, donkeys, and sheep. The levy for YHWH comes first, from the warrior's share. The principle of firstfruits: YHWH's portion comes off the top, before the division. 'Seek first the kingdom of God and his righteousness, and all these things will be added to you' (Matt 6:33). The YHWH-levy is the material form of seeking first.</p>",
"29": "<p>A shadow: Take it from their half and give it to Eleazar the priest as a contribution to YHWH. The priest receives YHWH's portion — the priesthood sustained from the firstfruits of victory. Christ as eternal priest is sustained by the Father's own life: 'as the living Father sent me, and I live because of the Father, so whoever feeds on me, he also will live because of me' (John 6:57).</p>",
"30": "<p>A shadow: From the congregation's half, take one out of every fifty of the persons, cattle, donkeys, and sheep and give them to the Levites. The congregation gives a double proportion to the Levites compared to what the warriors gave (one in fifty vs. one in five hundred). The Levites who served throughout — in camp, in worship — receive from the whole people. The church's giving to those who serve: 'the Lord commanded that those who proclaim the gospel should get their living by the gospel' (1 Cor 9:14).</p>",
"31": "<p>A theme: Moses and Eleazar did as YHWH commanded Moses. The faithful obedience in distributing the spoils — precisely, completely, according to YHWH's instruction. The distribution of victory gifts in the church is similarly governed by the Spirit's direction, not human preference: 'he distributes to each one individually as he wills' (1 Cor 12:11). The Lord of the harvest determines the distribution.</p>",
"32": "<p>A shadow: The plunder remaining from the spoil: 675,000 sheep, 72,000 cattle, 61,000 donkeys. The numbers are enormous — the victory is staggeringly fruitful. The eschatological harvest that Christ will bring in will be similarly immeasurable: 'a great multitude that no one could number, from every nation, from all tribes and peoples and languages' (Rev 7:9).</p>",
"33": "<p>A shadow: 72,000 cattle from the total. The cattle of the victory — the productive animals, the wealth-generators. In the kingdom, the productive inheritance of all creation returns to its rightful owner: 'the earth is the Lord's, and everything in it' (Ps 24:1). The victory plunder is a type of the eschatological inheritance of all creation.</p>",
"34": "<p>A shadow: 61,000 donkeys. The beast of burden that carried the work of the wilderness journey becomes plunder in the victory. The ordinary instruments of labor captured and redeemed. Nothing is too humble for inclusion in Christ's victory: the donkey that carried Jesus into Jerusalem (Matt 21:7) is the same animal whose kind appears in the numbers of the victory plunder.</p>",
"35": "<p>A shadow: 32,000 persons — the young women. The captives who were spared, now incorporated into the community. The Gentile inclusion: those who had been enemies or outside the covenant are received in. 'He came and preached peace to you who were far off and peace to those who were near' (Eph 2:17). The far-off made near through the victory of the Stronger Man.</p>",
"36": "<p>A theme: The warriors' half: 337,500 sheep, the levy for YHWH being 675. The precision of the accounting — every animal tallied, every fraction of the levy exact. God's accounting is precise: 'not one sparrow will fall to the ground apart from your Father' (Matt 10:29). The precision in Numbers 31 reflects the character of the God who keeps exact accounts.</p>",
"37": "<p>A theme: 675 sheep as levy to YHWH from the warriors' share, given to Eleazar the priest. The tiny levy — 675 out of 337,500, the smallest proportional offering — still matters to YHWH. 'She out of her poverty has put in everything she had' (Mark 12:44). The proportion matters; the faithfulness of the proportion is what YHWH receives.</p>",
"38": "<p>A shadow: 36,000 cattle, with the levy for YHWH being 72, given to Eleazar. The Levitical portion from the cattle — the productive, generative animals. The priestly portion from the best of what is won. Christ receives the firstfruits of humanity — those who belong to him from among all nations: 'the four living creatures and the twenty-four elders fell down before the Lamb' (Rev 5:8).</p>",
"39": "<p>A shadow: 30,500 donkeys, the levy being 61. Even the donkeys are levied — no animal is too humble to be included in YHWH's portion. The breadth of Christ's redemption: not just the dramatic and notable but the ordinary and humble. 'He who is faithful in a very little is also faithful in much' (Luke 16:10). The small levy of donkeys is the little that is given faithfully.</p>",
"40": "<p>A shadow: 16,000 persons, the levy for YHWH being 32, given to Eleazar. Thirty-two persons — a tiny number from sixteen thousand — given to the priest as YHWH's portion. The tithe of humanity given to the priestly service: the firstfruits of the redeemed presented before God. The 144,000 of Revelation 7 and 14 are the ultimate firstfruits: 'these have been redeemed from mankind as firstfruits for God and the Lamb' (Rev 14:4).</p>",
"41": "<p>A theme: Moses gives the levy — the contribution to YHWH — to Eleazar the priest as YHWH commanded. Moses's obedient distribution: every portion to its appointed recipient. The pattern of faithful stewardship: 'it is required of stewards that they be found faithful' (1 Cor 4:2). Moses administers what belongs to YHWH; the church administers what belongs to Christ.</p>",
"42": "<p>A shadow: The congregation's half: 337,500 sheep — their equal portion matching the warriors'. The equal division of victory between those who fought and those who remained affirms that the inheritance is not earned by individual merit but given by YHWH's grace. 'By grace you have been saved through faith. And this is not your own doing; it is the gift of God' (Eph 2:8).</p>",
"43": "<p>A theme: The congregation's half exactly mirrors the warriors' half. The equality of the division is not an accident but a deliberate structure: YHWH valued the contribution of both equally. The body of Christ: 'the parts of the body that seem to be weaker are indispensable' (1 Cor 12:22). The staying home is not less than the going out.</p>",
"44": "<p>A shadow: 36,000 cattle in the congregation's portion. The same number as the warriors' portion. The equality of the portions is emphasized through the detailed repetition of identical numbers. The gospel's equal provision: 'there is neither Jew nor Greek, there is neither slave nor free, there is no male and female, for you are all one in Christ Jesus' (Gal 3:28).</p>",
"45": "<p>A theme: 30,500 donkeys in the congregation's portion. The proportional equality extends to the lowliest animals — the donkeys are distributed equally. No category of gift, however humble, is reserved for the active warriors alone. The whole assembly shares in the full range of the victory's fruit.</p>",
"46": "<p>A theme: 16,000 persons in the congregation's portion. Equal numbers of persons in each half. The human element of the victory — the persons spared and incorporated — shared equally between the active participants and the whole assembly. The redemption is not a private possession of those most active in the church but the inheritance of every member.</p>",
"47": "<p>A shadow: Moses takes one of every fifty from the congregation's half — the Levitical levy — and gives it to the Levites as YHWH commanded. The congregation's levy to the Levites is larger proportionally than the warriors' levy to YHWH (one in fifty vs. one in five hundred). The whole congregation's sustained support of those who serve the sanctuary is the greater burden. 'Do you not know that those who are employed in the temple service get their food from the temple?' (1 Cor 9:13). The congregation's responsibility to sustain the ministry is proportionally larger than the warriors' special contribution.</p>",
"48": "<p>A shadow: The commanders of thousands and hundreds come before Moses. They present an accounting of the warriors — not one is missing. The perfect preservation of those who went out to battle: not one lost. Christ's own accounting: 'Of all that he has given me I should lose nothing, but raise it up on the last day' (John 6:39). The warrior count without a missing name is the temporal sign of the eternal completion.</p>",
"49": "<p>A direct type: 'Your servants have counted the warriors in our charge, and not a man of us is missing.' The report of zero casualties in a battle of twelve thousand against Midian — miraculous preservation. YHWH's perfect protection of those sent on his mission. Jesus promises the same to his apostles: 'I have guarded them, and not one of them has been lost except the son of destruction' (John 17:12). The Judas exception proves the rule — divine protection covers every true sheep.</p>",
"50": "<p>A direct type: The commanders bring a voluntary offering from the plunder — gold objects, armlets, bracelets, signet rings, earrings, and beads — to make atonement (<em>lekhaper</em>) for themselves before YHWH. The spontaneous offering of gold jewelry for atonement foreshadows the gifts of the Magi (Matt 2:11: gold, frankincense, myrrh) presented before the one who is himself the atonement. The warriors' gold becomes the Magi's gold — both brought voluntarily before the one who makes atonement possible.</p>",
"51": "<p>A theme: Moses and Eleazar receive all the worked gold from the commanders. The priests receive the offerings made for atonement. The eternal high priest Christ receives the gift of the penitent: the broken and contrite heart he does not despise (Ps 51:17). The gold offered by the soldiers — grateful survivors bringing what they have — is the posture of all who come to the throne of grace.</p>",
"52": "<p>A shadow: All the gold of the offering was 16,750 shekels — from the commanders. The pure act of grateful worship: the ones who survived give back from what they received. Gratitude as the shape of worship: 'you have been bought with a price. So glorify God in your body' (1 Cor 6:20). The survivors who give back from their plunder are the type of the redeemed who offer their bodies as living sacrifices.</p>",
"53": "<p>A theme: The ordinary soldiers had each taken plunder for themselves. The commanders' offering was voluntary and additional — above what each man had already kept. The gift beyond what was required: the alabaster jar of ointment, the widow's two coins, the Macedonian churches giving beyond their means (2 Cor 8:3). Generosity beyond calculation is the mark of those who understand what they have received.</p>",
"54": "<p>A direct type: Moses and Eleazar bring the gold into the tent of meeting as a memorial (<em>zikaron</em>) for the Israelites before YHWH. The victory offering stored in the sanctuary as a permanent memorial of YHWH's faithfulness. Christ's wounds remain after the resurrection as a memorial of his victory — Thomas is invited to touch them (John 20:27). The scars of battle become the memorials of accomplished redemption, presented forever before the Father.</p>"
}
}

comm = load_comm('mkt-christ', 'numbers')
merge_comm(comm, CHRIST)
save_comm('mkt-christ', 'numbers', comm)
print('Numbers 30-31 mkt-christ written.')
